// === Battery-room alarm FSM ===
// Synced from dashboard/lib/alarm-fsm.js — scripts/check.sh enforces equality.
// SYNC-START
function stepAlarm(ctx) {
    const motion = !!(ctx.motionMain || ctx.motionAux);
    const door = !!ctx.doorOpen;
    let state = ctx.state || 'disarmed';
    let stateSince = ctx.stateSince || ctx.now;
    let triggerReason = ctx.triggerReason || '';
    const set = (s, reason) => {
        state = s;
        stateSince = ctx.now;
        if (reason !== undefined) triggerReason = reason;
    };
    switch (state) {
        case 'disarmed': {
            if (ctx.autoArmEnabled && !door && !motion) set('arming');
            break;
        }
        case 'arming': {
            if (door || motion) {
                stateSince = ctx.now;
                break;
            }
            const elapsedMs = ctx.now - stateSince;
            const requiredMs = (ctx.armingQuietMinutes || 5) * 60 * 1000;
            if (elapsedMs >= requiredMs) set('armed');
            break;
        }
        case 'armed': {
            const sinceArmedMs = ctx.now - stateSince;
            const graceMs = (ctx.armingGraceSeconds || 10) * 1000;
            if (sinceArmedMs < graceMs) break;
            const reasons = [];
            if (door) reasons.push('otwarcie drzwi');
            if (ctx.motionMain) reasons.push('ruch (główny)');
            if (ctx.motionAux) reasons.push('ruch (zapasowy)');
            if (reasons.length) set('triggered', reasons.join(' · '));
            break;
        }
        case 'triggered': { break; }
    }
    let sirenOn = false;
    if (state === 'triggered') {
        const sirenMs = (ctx.sirenDurationS || 60) * 1000;
        sirenOn = (ctx.now - stateSince) < sirenMs;
    }
    return { state, stateSince, sirenOn, triggerReason, transitioned: state !== (ctx.state || 'disarmed'), };
}
// SYNC-END

const ha = global.get('homeassistant')?.homeAssistant?.states;
if (!ha) {
    node.warn('HA global state unavailable — enable "Expose to Node-RED" in server config');
    return null;
}

const num = (id, def) => {
    const s = ha[id]?.state;
    const n = parseFloat(s);
    return Number.isFinite(n) ? n : def;
};
const isOn = (id) => ha[id]?.state === 'on';
const stateOf = (id) => ha[id]?.state;

const now = Date.now();
const persisted = flow.get('alarm_state_meta') || {};
const stateFromHA = stateOf('input_select.alarm_state') || 'disarmed';

// If HA state diverges from our last-seen (because the user wrote it from
// the dashboard), treat it as the new starting point and reset stateSince.
let stateSince = persisted.stateSince || now;
if (persisted.lastState !== stateFromHA) {
    stateSince = now;
}

const ctx = {
    now,
    state: stateFromHA,
    stateSince,
    doorOpen:           isOn('binary_sensor.battery_room_door_contact'),
    motionMain:         isOn('binary_sensor.battery_room_motion_main_occupancy'),
    motionAux:          isOn('binary_sensor.battery_room_motion_aux_occupancy'),
    autoArmEnabled:     isOn('input_boolean.alarm_auto_arm_enabled'),
    armingQuietMinutes: num('input_number.alarm_arming_quiet_minutes', 5),
    armingGraceSeconds: num('input_number.alarm_arming_grace_seconds', 10),
    sirenDurationS:     num('input_number.alarm_siren_duration_s', 60),
    triggerReason:      ha['input_text.alarm_trigger_reason']?.state || '',
};

const result = stepAlarm(ctx);
flow.set('alarm_state_meta', { lastState: result.state, stateSince: result.stateSince });

// Decide what to push downstream.
const stateChanged = result.state !== stateFromHA;
const nowTriggered = stateChanged && result.state === 'triggered';
const leftTriggered = stateChanged && stateFromHA === 'triggered';
const sirenWasOn = flow.get('alarm_siren_on') === true;
const sirenStateChanged = result.sirenOn !== sirenWasOn;
flow.set('alarm_siren_on', result.sirenOn);

node.status({
    fill: result.state === 'triggered' ? 'red'
        : result.state === 'armed' ? 'green'
        : result.state === 'arming' ? 'yellow'
        : 'grey',
    shape: 'dot',
    text: `${result.state} | door=${ctx.doorOpen?'open':'closed'} m1=${ctx.motionMain?'1':'0'} m2=${ctx.motionAux?'1':'0'} siren=${result.sirenOn?'on':'off'}`
});

const out = [null, null, null, null];
if (stateChanged) {
    out[0] = { topic: 'state', payload: result.state };
    out[1] = { topic: 'reason', payload: result.triggerReason };
}
if (sirenStateChanged) {
    out[2] = result.sirenOn
        ? { topic: 'zigbee2mqtt/battery_room_siren/set',
            payload: JSON.stringify({ warning: { mode: 'emergency', level: 'high', duration: Math.round(ctx.sirenDurationS) } }) }
        : { topic: 'zigbee2mqtt/battery_room_siren/set',
            payload: JSON.stringify({ warning: { mode: 'stop' } }) };
}
if (nowTriggered) {
    out[3] = { payload: { reason: result.triggerReason } };
}
return out;
